import React from "react";
import ListGroup from "react-bootstrap/ListGroup";
import Card from "react-bootstrap/Card";
import Button from "react-bootstrap/Button";
import rui from "../imgs/rui.png";
import chatApp from "../imgs/chat-app.png";
import reactbackend from "../imgs/react-backend.png";
import designer from "../imgs/designer.png";
export default function Projects() {
  return (
    <ListGroup>
      <ListGroup.Item>
        <Card>
          <Card.Img variant="top" src={chatApp}></Card.Img>
          <Card.Body>
            <Card.Title>Chat-UI</Card.Title>
            <Card.Text>
              A React component library designed for developers who want their
              chatting app built ASAP.
            </Card.Text>
            <Button
              variant="primary"
              className="mr-4"
              onClick={() => window.open("https://chat-ui-site.vercel.app/")}
            >
              View Site
            </Button>
            <Button
              variant="primary"
              onClick={() =>
                window.open("https://github.com/ruidashen/Chat-UI")
              }
            >
              Github
            </Button>
          </Card.Body>
        </Card>
      </ListGroup.Item>
      <ListGroup.Item>
        <Card>
          <Card.Img variant="top" src={rui}></Card.Img>
          <Card.Body>
            <Card.Title>R-UI</Card.Title>
            <Card.Text>
              A component library written in Vue 3.0 with composition APIs(
              setup, watchEffect, ref, computed) and TypeScript
            </Card.Text>
            <Button
              variant="primary"
              className="mr-4"
              onClick={() => window.open("https://r-ui-site.vercel.app/#/")}
            >
              View Site
            </Button>
            <Button
              variant="primary"
              onClick={() => window.open("https://github.com/ruidashen/R-UI")}
            >
              Github
            </Button>
          </Card.Body>
        </Card>
      </ListGroup.Item>
      <ListGroup.Item>
        <Card>
          <Card.Img variant="top" src={reactbackend}></Card.Img>
          <Card.Body>
            <Card.Title>React Backend Management</Card.Title>
            <Card.Text>
              This project is full stack MERN app, it is a mock up backend for
              e-commerce website. Functionalities include:
            </Card.Text>
            <div className="mb-3">
              <ol className="ml-5">
                <li>user login</li>
                <li>product category management</li>
                <li>product management </li>
                <li>role management</li>
                <li>user management</li>
                <li>menu access control</li>
              </ol>
              <strong>
                <em>default username: admin, password:admin</em>
              </strong>
            </div>
            <Button
              variant="primary"
              className="mr-4"
              onClick={() => window.open("http://13.59.50.112/")}
            >
              View Site
            </Button>
            <Button
              variant="primary"
              onClick={() =>
                window.open(
                  "https://github.com/ruidashen/react-backend-managment-system"
                )
              }
            >
              Github
            </Button>
          </Card.Body>
        </Card>
      </ListGroup.Item>
      <ListGroup.Item>
        <Card>
          <Card.Img variant="top" src={designer}></Card.Img>
          <Card.Body>
            <Card.Title>Designer/Artist gallery</Card.Title>
            <Card.Text>
              A gallery template built for people who want to put their work
              online
            </Card.Text>
            <Button
              variant="primary"
              className="mr-4"
              onClick={() =>
                window.open("https://designer-showcase.herokuapp.com/")
              }
            >
              View Site
            </Button>
            <Button
              variant="primary"
              onClick={() =>
                window.open("https://github.com/ruidashen/designer-showcase")
              }
            >
              Github
            </Button>
          </Card.Body>
        </Card>
      </ListGroup.Item>
    </ListGroup>
  );
}
