import React from "react";
import Card from "react-bootstrap/Card";
import profilePic from "../imgs/4-286x180.jpg";
export default function Profile() {
  return (
    <div className="mb-2">
      <Card>
        <Card.Img variant="top" src={profilePic} />
        <Card.Body>
          <Card.Title>About Me</Card.Title>
          <Card.Text>
            My name is Ruida Shen. I am interested in Web development, this
            website has all my projects and work experience, I am looking for a
            junior front end developer job or related internship.
          </Card.Text>
        </Card.Body>
      </Card>

      <h3 className="mt-3">Skills</h3>
      <ul className="mt-3 skills">
        <li>
          <strong>Programming Languages</strong>: JavaScript(ES6+), Java
        </li>
        <li>
          <strong>Front End Libraries / Frameworks</strong>: React, Vue
        </li>
        <li>
          <strong>Back End Development</strong>: Node, Express
        </li>
        <li>
          <strong>CSS Libraries</strong>: Bootstrap, Ant Design
        </li>
        <li>
          <strong>Development Tools</strong>: Axios, Postman, React (Vue) Dev
          Tools, Webpack
        </li>
        <li>
          <strong>Databases</strong>: MySql, MongoDB
        </li>
        <li>
          <strong>Version Control</strong>: Git
        </li>
        <li>
          <strong>Unit Testing</strong>: Mocha
        </li>
        <li>
          <strong>Cloud Services</strong>: AWS
        </li>
      </ul>
      <h2 className="mt-3">Education</h2>
      <p>
        Cal State Eastbay, Hayward, California <br />
        Aug 2018 - May 2020
      </p>
    </div>
  );
}
